use std::mem;
use std::io;
use std::string;
use std::cmp::*;

fn load() -> Vec<i32> {
    let mut line = String::new();
    io::stdin().read_line(&mut line).expect("Failed to read line");
    let vec: Vec<&str> = line.split(" ").collect();
    let mut data : Vec<i32> = Vec::new();
    for i in vec {
        let el : i32 = i.trim().parse().unwrap();
        data.push(el);
    }
    data
}

fn main() {
    let ar = load();
    let (q,k) = (ar[0],ar[1]);
    let mut a = q;
    let mut b = 0;
    let mut last=-1;
    while last != b {
        last=b;
        b = (a + b)/k;
    }
    println!("{}", a+b);
}
